package com.bankapp;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import java.math.BigDecimal;
import java.math.RoundingMode;

public class BankingActivity extends AppCompatActivity {
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String BALANCE_KEY = "account_balance";
    private static final String TRANSACTION_HISTORY_KEY = "transaction_history";
    
    private TextView balanceTextView;
    private EditText amountEditText;
    private Button depositButton;
    private Button withdrawButton;
    private Button checkBalanceButton;
    
    private SharedPreferences sharedPreferences;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);
        
        initializeViews();
        setupSharedPreferences();
        setupClickListeners();
        updateBalanceDisplay();
    }
    
    private void initializeViews() {
        balanceTextView = findViewById(R.id.balanceTextView);
        amountEditText = findViewById(R.id.amountEditText);
        depositButton = findViewById(R.id.depositButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        checkBalanceButton = findViewById(R.id.checkBalanceButton);
    }
    
    private void setupSharedPreferences() {
        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }
    
    private void setupClickListeners() {
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processDeposit();
            }
        });
        
        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processWithdrawal();
            }
        });
        
        checkBalanceButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                updateBalanceDisplay();
            }
        });
    }
    
    private void processDeposit() {
        String amountString = amountEditText.getText().toString().trim();
        if (amountString.isEmpty()) {
            showError("Please enter an amount");
            return;
        }
        
        try {
            BigDecimal amount = new BigDecimal(amountString);
            if (amount.compareTo(BigDecimal.ZERO) <= 0) {
                showError("Amount must be greater than zero");
                return;
            }
            
            BigDecimal currentBalance = getAccountBalance();
            BigDecimal newBalance = currentBalance.add(amount);
            
            saveBalance(newBalance);
            updateBalanceDisplay();
            clearAmountField();
            showSuccess("Deposit successful");
            
        } catch (NumberFormatException e) {
            showError("Invalid amount format");
        }
    }
    
    private void processWithdrawal() {
        String amountString = amountEditText.getText().toString().trim();
        if (amountString.isEmpty()) {
            showError("Please enter an amount");
            return;
        }
        
        try {
            BigDecimal amount = new BigDecimal(amountString);
            if (amount.compareTo(BigDecimal.ZERO) <= 0) {
                showError("Amount must be greater than zero");
                return;
            }
            
            BigDecimal currentBalance = getAccountBalance();
            if (amount.compareTo(currentBalance) > 0) {
                showError("Insufficient funds");
                return;
            }
            
            BigDecimal newBalance = currentBalance.subtract(amount);
            saveBalance(newBalance);
            updateBalanceDisplay();
            clearAmountField();
            showSuccess("Withdrawal successful");
            
        } catch (NumberFormatException e) {
            showError("Invalid amount format");
        }
    }
    
    private BigDecimal getAccountBalance() {
        String balanceString = sharedPreferences.getString(BALANCE_KEY, "0.00");
        return new BigDecimal(balanceString).setScale(2, RoundingMode.HALF_UP);
    }
    
    private void saveBalance(BigDecimal balance) {
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(BALANCE_KEY, balance.toString());
        editor.apply();
    }
    
    private void updateBalanceDisplay() {
        BigDecimal balance = getAccountBalance();
        balanceTextView.setText(String.format("Balance: $%.2f", balance));
    }
    
    private void clearAmountField() {
        amountEditText.setText("");
    }
    
    private void showSuccess(String message) {
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show();
    }
    
    private void showError(String message) {
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show();
    }
}